     6→import { useOnboardingStore } from '@/lib/stores/onboarding-store';
     7→import {
     8→  GraduationCap,
     9→  BookOpen,
    10→  Brain,
    11→  Trophy,
    12→  Settings,
    13→  PanelLeftClose,
    14→  PanelLeftOpen,
