    31→import { NotificationBell } from '@/components/notifications/notification-bell';
    32→import { PomodoroHeaderWidget } from '@/components/pomodoro';
    33→import { AmbientAudioHeaderWidget } from '@/components/ambient-audio';
    34→import {
    35→  LazyQuizView,
    36→  LazyFlashcardsView,
    37→  LazyMindmapsView,
    38→  LazySummariesView,
    39→  LazyHomeworkHelpView,
    40→  LazyCalendarView,
    41→  LazyHTMLSnippetsView,
    42→} from '@/components/education';
    43→import { CharacterChatView } from '@/components/conversation';
    44→import { LazySettingsView } from '@/components/settings';
    45→import { LazyProgressView } from '@/components/progress';
    46→import { Button } from '@/components/ui/button';
    47→import { useProgressStore, useSettingsStore, useUIStore } from '@/lib/stores/app-store';
    48→import { useConversationFlowStore } from '@/lib/stores/conversation-flow-store';
    49→import { FocusToolLayout } from '@/components/tools/focus-tool-layout';
    50→import { useParentInsightsIndicator } from '@/lib/hooks/use-parent-insights-indicator';
