    52→
    53→type View = 'coach' | 'buddy' | 'maestri' | 'maestro-session' | 'quiz' | 'flashcards' | 'mindmaps' | 'summaries' | 'homework' | 'studykit' | 'calendar' | 'demos' | 'progress' | 'genitori' | 'settings';
    54→type MaestroSessionMode = 'voice' | 'chat';
    55→
    56→// Character info for sidebar display
    57→const COACH_INFO = {
    58→  melissa: { name: 'Melissa', avatar: '/avatars/melissa.jpg' },
    59→  roberto: { name: 'Roberto', avatar: '/avatars/roberto.png' },
    60→  chiara: { name: 'Chiara', avatar: '/avatars/chiara.png' },
    61→  andrea: { name: 'Andrea', avatar: '/avatars/andrea.png' },
    62→  favij: { name: 'Favij', avatar: '/avatars/favij.jpg' },
    63→} as const;
    64→
    65→const BUDDY_INFO = {
    66→  mario: { name: 'Mario', avatar: '/avatars/mario.jpg' },
    67→  noemi: { name: 'Noemi', avatar: '/avatars/noemi.png' },
    68→  enea: { name: 'Enea', avatar: '/avatars/enea.png' },
    69→  bruno: { name: 'Bruno', avatar: '/avatars/bruno.png' },
    70→  sofia: { name: 'Sofia', avatar: '/avatars/sofia.png' },
    71→} as const;
    72→
    73→export default function Home() {
    74→  const router = useRouter();
    75→  const { hasCompletedOnboarding, isHydrated, hydrateFromApi } = useOnboardingStore();
    76→
    77→  // Hydrate onboarding state from DB on mount
    78→  useEffect(() => {
    79→    hydrateFromApi();
    80→  }, [hydrateFromApi]);
    81→
    82→  // Redirect to welcome if onboarding not completed (only after hydration)
    83→  useEffect(() => {
    84→    if (isHydrated && !hasCompletedOnboarding) {
    85→      router.push('/welcome');
    86→    }
    87→  }, [isHydrated, hasCompletedOnboarding, router]);
    88→
    89→  // Start with Maestri as the first view
    90→  const [currentView, setCurrentView] = useState<View>('maestri');
    91→  const [sidebarOpen, setSidebarOpen] = useState(true);
    92→
    93→  // Maestro session state
    94→  const [selectedMaestro, setSelectedMaestro] = useState<Maestro | null>(null);
    95→  const [maestroSessionMode, setMaestroSessionMode] = useState<MaestroSessionMode>('voice');
    96→  const [maestroSessionKey, setMaestroSessionKey] = useState(0);
    97→
    98→  const { xp, level, streak, totalStudyMinutes, sessionsThisWeek, questionsAsked } = useProgressStore();
    99→  const { studentProfile } = useSettingsStore();
   100→  const { hasNewInsights, markAsViewed } = useParentInsightsIndicator();
   101→  const { focusMode } = useUIStore();
   102→  const {
   103→    activeCharacter,
   104→    conversationsByCharacter,
   105→    endConversationWithSummary,
   106→    isActive: isConversationActive
   107→  } = useConversationFlowStore();
   108→
   109→  // Handler to close active conversation before navigating to a different view
   110→  const handleViewChange = async (newView: View) => {
   111→    // If there's an active conversation, close it first
   112→    if (isConversationActive && activeCharacter) {
   113→      const characterConvo = conversationsByCharacter[activeCharacter.id];
   114→      if (characterConvo?.conversationId) {
   115→        const userId = sessionStorage.getItem('convergio-user-id');
   116→        if (userId) {
   117→          try {
   118→            await endConversationWithSummary(characterConvo.conversationId, userId);
   119→          } catch (error) {
   120→            console.error('Failed to close conversation:', error);
   121→          }
   122→        }
   123→      }
   124→    }
   125→    setCurrentView(newView);
   126→  };
   127→
   128→  // Don't render main app until hydration is done and onboarding is completed
   129→  if (!isHydrated || !hasCompletedOnboarding) {
   130→    return null;
   131→  }
   132→
   133→  // XP calculations
   134→  const XP_PER_LEVEL = [0, 100, 250, 500, 1000, 2000, 4000, 8000, 16000, 32000, 64000];
   135→  const currentLevelXP = XP_PER_LEVEL[level - 1] || 0;
   136→  const nextLevelXP = XP_PER_LEVEL[level] || XP_PER_LEVEL[XP_PER_LEVEL.length - 1];
   137→  const xpInLevel = xp - currentLevelXP;
   138→  const xpNeeded = nextLevelXP - currentLevelXP;
   139→  const progressPercent = Math.min(100, (xpInLevel / xpNeeded) * 100);
   140→
   141→  // Format study time
   142→  const hours = Math.floor(totalStudyMinutes / 60);
   143→  const minutes = totalStudyMinutes % 60;
   144→  const studyTimeStr = hours > 0 ? `${hours}h${minutes}m` : `${minutes}m`;
   145→
   146→  // Get selected coach and buddy from preferences (with defaults)
   147→  const selectedCoach = studentProfile?.preferredCoach || 'melissa';
   148→  const selectedBuddy = studentProfile?.preferredBuddy || 'mario';
   149→  const coachInfo = COACH_INFO[selectedCoach];
   150→  const buddyInfo = BUDDY_INFO[selectedBuddy];
   151→
   152→  const navItems = [
   153→    { id: 'coach' as const, label: coachInfo.name, icon: Sparkles, isChat: true, avatar: coachInfo.avatar },
   154→    { id: 'buddy' as const, label: buddyInfo.name, icon: Heart, isChat: true, avatar: buddyInfo.avatar },
   155→    { id: 'maestri' as const, label: 'Professori', icon: GraduationCap },
   156→    { id: 'quiz' as const, label: 'Quiz', icon: Brain },
   157→    { id: 'flashcards' as const, label: 'Flashcards', icon: BookOpen },
   158→    { id: 'mindmaps' as const, label: 'Mappe Mentali', icon: Network },
   159→    { id: 'summaries' as const, label: 'Riassunti', icon: FileText },
   160→    { id: 'homework' as const, label: 'Materiali', icon: Target },
   161→    { id: 'studykit' as const, label: 'Study Kit', icon: Upload },
   162→    { id: 'calendar' as const, label: 'Calendario', icon: Calendar },
   163→    { id: 'demos' as const, label: 'Demo', icon: Brain },
   164→    { id: 'progress' as const, label: 'Progressi', icon: Trophy },
   165→    { id: 'genitori' as const, label: 'Genitori', icon: Users },
   166→    { id: 'settings' as const, label: 'Impostazioni', icon: Settings },
   167→  ];
   168→
   169→  return (
   170→    <div className="min-h-screen bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-950">
   171→      {/* Unified Header Bar */}
   172→      <header
   173→        className={cn(
   174→          'fixed top-0 right-0 h-14 z-50 flex items-center justify-between px-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200/50 dark:border-slate-700/50 transition-all duration-300',
   175→          sidebarOpen ? 'left-64' : 'left-20'
   176→        )}
   177→      >
   178→        {/* Level + XP Progress */}
   179→        <div className="flex items-center gap-3 min-w-[200px]">
   180→          <div className="w-8 h-8 rounded-full bg-accent-themed flex items-center justify-center flex-shrink-0">
   181→            <Trophy className="w-4 h-4 text-white" />
   182→          </div>
   183→          <div className="flex-1 min-w-0">
   184→            <div className="flex items-baseline gap-2 text-sm">
   185→              <span className="font-bold text-slate-900 dark:text-white">Lv.{level}</span>
   186→              <span className="text-xs text-slate-500">{xpInLevel}/{xpNeeded} XP</span>
   187→            </div>
   188→            <div className="h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden mt-0.5 w-32">
   189→              <motion.div
   190→                className="h-full bg-accent-themed rounded-full"
   191→                initial={{ width: 0 }}
   192→                animate={{ width: `${progressPercent}%` }}
   193→                transition={{ duration: 0.5 }}
   194→              />
   195→            </div>
   196→          </div>
   197→        </div>
   198→
   199→        {/* Quick Stats */}
   200→        <div className="flex items-center gap-4 text-sm">
   201→          <div className="flex items-center gap-1.5" title="Streak">
   202→            <Flame className={cn("w-4 h-4", streak.current > 0 ? "text-orange-500" : "text-slate-400")} />
   203→            <span className={cn("font-semibold", streak.current > 0 ? "text-orange-500" : "text-slate-500")}>
   204→              {streak.current}
   205→            </span>
   206→          </div>
   207→
   208→          <div className="flex items-center gap-1.5" title="Sessioni questa settimana">
   209→            <BookOpen className="w-4 h-4 text-accent-themed" />
   210→            <span className="font-semibold text-slate-700 dark:text-slate-300">{sessionsThisWeek}</span>
   211→          </div>
   212→
   213→          <div className="flex items-center gap-1.5" title="Tempo di studio">
   214→            <Clock className="w-4 h-4 text-green-500" />
   215→            <span className="font-semibold text-slate-700 dark:text-slate-300">{studyTimeStr}</span>
   216→          </div>
   217→
   218→          <div className="flex items-center gap-1.5" title="Domande fatte">
   219→            <Star className="w-4 h-4 text-purple-500" />
   220→            <span className="font-semibold text-slate-700 dark:text-slate-300">{questionsAsked}</span>
   221→          </div>
   222→
   223→          {/* Streak bonus badge */}
   224→          {streak.current >= 3 && (
   225→            <div className="flex items-center gap-1 px-2 py-0.5 rounded-full bg-orange-100 dark:bg-orange-900/30 text-orange-600 dark:text-orange-400 text-xs font-medium">
   226→              <Flame className="w-3 h-3" />
   227→              +{Math.min(streak.current * 10, 50)}% XP
   228→            </div>
   229→          )}
   230→        </div>
   231→
   232→        {/* Right section: ambient audio + pomodoro + notifications + version */}
   233→        <div className="flex items-center gap-3">
   234→          <AmbientAudioHeaderWidget />
   235→          <PomodoroHeaderWidget />
   236→          <NotificationBell />
   237→          <span className="text-xs text-slate-400 dark:text-slate-500 font-mono">
   238→            v{process.env.APP_VERSION}
   239→          </span>
   240→        </div>
   241→      </header>
   242→
   243→      {/* Sidebar */}
   244→      <aside
   245→        className={cn(
   246→          'fixed top-0 left-0 h-full bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 z-40 transition-all duration-300',
   247→          sidebarOpen ? 'w-64' : 'w-20'
   248→        )}
   249→      >
   250→        {/* Logo - clickable to return home */}
   251→        <div className="h-14 flex items-center justify-between px-4 border-b border-slate-200 dark:border-slate-800">
   252→          <button
   253→            onClick={() => setCurrentView('maestri')}
   254→            className="flex items-center gap-3 hover:opacity-80 transition-opacity"
   255→            aria-label="Torna alla home"
   256→          >
   257→            <div className="w-9 h-9 rounded-xl overflow-hidden flex-shrink-0">
   258→              <Image
   259→                src="/logo-brain.png"
   260→                alt="MirrorBuddy"
   261→                width={36}
   262→                height={36}
   263→                className="w-full h-full object-cover"
   264→              />
   265→            </div>
   266→            {sidebarOpen && (
   267→              <span className="font-bold text-lg text-slate-900 dark:text-white">
   268→                MirrorBuddy
   269→              </span>
   270→            )}
   271→          </button>
   272→          <Button
   273→            variant="ghost"
   274→            size="icon-sm"
   275→            onClick={() => setSidebarOpen(!sidebarOpen)}
   276→            className="text-slate-500"
   277→            aria-label={sidebarOpen ? 'Chiudi menu' : 'Apri menu'}
   278→          >
   279→            {sidebarOpen ? <PanelLeftClose className="h-4 w-4" /> : <PanelLeftOpen className="h-4 w-4" />}
   280→          </Button>
   281→        </div>
   282→
   283→        {/* Navigation - with bottom padding for XP bar */}
   284→        <nav className="p-4 space-y-2 overflow-y-auto pb-24" style={{ maxHeight: 'calc(100vh - 120px)' }}>
   285→          {navItems.map((item) => {
   286→            const isChatItem = item.id === 'coach' || item.id === 'buddy';
   287→            const avatarSrc = 'avatar' in item ? item.avatar : null;
   288→
   289→            return (
   290→              <button
   291→                key={item.id}
   292→                onClick={async () => {
   293→                  if (item.id === 'genitori') {
   294→                    markAsViewed();
   295→                    // Close active conversation before navigating away
   296→                    await handleViewChange('genitori');
   297→                    router.push('/parent-dashboard');
   298→                  } else if (item.id === 'studykit') {
   299→                    await handleViewChange('studykit');
   300→                    router.push('/study-kit');
   301→                  } else {
   302→                    await handleViewChange(item.id);
   303→                  }
   304→                }}
   305→                className={cn(
   306→                  'w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all',
   307→                  currentView === item.id
   308→                    ? 'bg-accent-themed text-white shadow-lg'
   309→                    : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800',
   310→                  isChatItem && 'relative'
   311→                )}
   312→                style={currentView === item.id ? { boxShadow: '0 10px 15px -3px var(--accent-color, #3b82f6)40' } : undefined}
   313→              >
   314→                {avatarSrc ? (
   315→                  <div className="relative flex-shrink-0">
   316→                    <Image
   317→                      src={avatarSrc}
   318→                      alt={item.label}
   319→                      width={32}
   320→                      height={32}
   321→                      className="w-8 h-8 rounded-full object-cover"
   322→                    />
   323→                    <span className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-400 border-2 border-white dark:border-slate-900 rounded-full" />
   324→                  </div>
   325→                ) : (
   326→                  <div className="relative flex-shrink-0">
   327→                    <item.icon className="h-5 w-5" />
   328→                    {item.id === 'genitori' && hasNewInsights && (
   329→                      <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-red-500 rounded-full animate-pulse" />
   330→                    )}
   331→                  </div>
   332→                )}
   333→                {sidebarOpen && <span className="font-medium">{item.label}</span>}
   334→              </button>
   335→            );
   336→          })}
   337→        </nav>
   338→
   339→        {/* XP Progress */}
   340→        {sidebarOpen && (
   341→          <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   342→            <div className="mb-2 flex justify-between text-sm">
   343→              <span className="text-slate-600 dark:text-slate-400">XP</span>
   344→              <span className="font-medium text-slate-900 dark:text-white">
   345→                {xp.toLocaleString()}
   346→              </span>
   347→            </div>
   348→            <div className="h-2 rounded-full bg-slate-200 dark:bg-slate-700 overflow-hidden">
   349→              <motion.div
   350→                className="h-full bg-accent-themed"
   351→                initial={{ width: 0 }}
   352→                animate={{ width: `${(xp % 1000) / 10}%` }}
   353→              />
   354→            </div>
   355→          </div>
   356→        )}
   357→      </aside>
   358→
   359→      {/* Main content */}
   360→      <main
   361→        className={cn(
   362→          'min-h-screen transition-all duration-300 p-8 pt-20',
   363→          sidebarOpen ? 'ml-64' : 'ml-20'
   364→        )}
   365→      >
   366→
   367→        {/* View content */}
   368→        <motion.div
   369→          key={currentView}
   370→          initial={{ opacity: 0, y: 20 }}
   371→          animate={{ opacity: 1, y: 0 }}
   372→          transition={{ duration: 0.3 }}
   373→        >
   374→          {currentView === 'coach' && (
   375→            <CharacterChatView characterId={selectedCoach} characterType="coach" />
   376→          )}
   377→
   378→          {currentView === 'buddy' && (
   379→            <CharacterChatView characterId={selectedBuddy} characterType="buddy" />
   380→          )}
   381→
   382→          {currentView === 'maestri' && (
   383→            <MaestriGrid
   384→              onMaestroSelect={(maestro, mode) => {
   385→                setSelectedMaestro(maestro);
   386→                setMaestroSessionMode(mode);
   387→                setMaestroSessionKey(prev => prev + 1);
   388→                setCurrentView('maestro-session');
   389→              }}
   390→            />
   391→          )}
   392→
   393→          {currentView === 'maestro-session' && selectedMaestro && (
   394→            <MaestroSession
   395→              key={`maestro-${selectedMaestro.id}-${maestroSessionKey}`}
   396→              maestro={selectedMaestro}
   397→              onClose={() => setCurrentView('maestri')}
   398→              initialMode={maestroSessionMode}
   399→            />
   400→          )}
   401→
   402→          {currentView === 'quiz' && <LazyQuizView />}
   403→
   404→          {currentView === 'flashcards' && <LazyFlashcardsView />}
   405→
   406→          {currentView === 'mindmaps' && <LazyMindmapsView />}
   407→
   408→          {currentView === 'summaries' && <LazySummariesView />}
   409→
   410→          {currentView === 'homework' && <LazyHomeworkHelpView />}
   411→
   412→          {currentView === 'calendar' && <LazyCalendarView />}
   413→
   414→          {currentView === 'demos' && <LazyHTMLSnippetsView />}
   415→
   416→          {currentView === 'progress' && <LazyProgressView />}
   417→
   418→          {currentView === 'settings' && <LazySettingsView />}
   419→        </motion.div>
   420→      </main>
   421→
   422→      {/* Focus Mode Overlay - renders above everything when active */}
   423→      {focusMode && <FocusToolLayout />}
   424→    </div>
   425→  );
   426→}
   427→

