     1→'use client';
     2→
     3→import { Suspense, useEffect, useState, useCallback, useRef } from 'react';
     4→import { useRouter, useSearchParams } from 'next/navigation';
     5→import { motion, AnimatePresence } from 'framer-motion';
     6→import Image from 'next/image';
     7→import { RotateCcw, Wifi, WifiOff, Cloud, Volume2, ArrowRight, Settings, Sparkles } from 'lucide-react';
     8→import { useOnboardingStore, getStepIndex, getTotalSteps } from '@/lib/stores/onboarding-store';
     9→import { useVoiceSession } from '@/lib/hooks/use-voice-session';
    10→import { WelcomeStep } from './components/welcome-step';
    11→import { InfoStep } from './components/info-step';
    12→import { PrinciplesStep } from './components/principles-step';
    13→import { MaestriStep } from './components/maestri-step';
    14→import { ReadyStep } from './components/ready-step';
    15→import { Button } from '@/components/ui/button';
    16→import { cn } from '@/lib/utils';
    17→import { logger } from '@/lib/logger';
    18→import type { VoiceSessionHandle } from '@/types';
    19→import type { Maestro, Subject, MaestroVoice } from '@/types';
    20→import {
    21→  generateMelissaOnboardingPrompt,
    22→  MELISSA_ONBOARDING_VOICE_INSTRUCTIONS,
    23→  type ExistingUserDataForPrompt,
    24→} from '@/lib/voice/onboarding-tools';
    25→
    26→interface VoiceConnectionInfo {
    27→  provider: 'azure';
    28→  proxyPort: number;
    29→  configured: boolean;
    30→}
    31→
    32→// Data returned from /api/onboarding
    33→interface ExistingUserData {
    34→  name: string;
    35→  age?: number;
    36→  schoolLevel?: 'elementare' | 'media' | 'superiore';
    37→  learningDifferences?: string[];
    38→  gender?: 'male' | 'female' | 'other';
    39→}
    40→
    41→/**
    42→ * Create Melissa maestro for onboarding with specialized prompts.
    43→ * If existingUserData is provided, Melissa will greet them by name and ask if they want to update.
    44→ */
    45→function createOnboardingMelissa(existingUserData?: ExistingUserDataForPrompt | null): Maestro {
    46→  const isReturningUser = Boolean(existingUserData?.name);
    47→
    48→  return {
    49→    id: 'melissa-onboarding',
    50→    name: 'Melissa',
    51→    subject: 'methodology' as Subject,
    52→    specialty: 'Learning Coach - Onboarding',
    53→    voice: 'shimmer' as MaestroVoice,
    54→    voiceInstructions: MELISSA_ONBOARDING_VOICE_INSTRUCTIONS,
    55→    teachingStyle: 'scaffolding',
    56→    avatar: '/avatars/melissa.jpg',
    57→    color: '#EC4899',
    58→    // Use dynamic prompt that adapts for returning users
    59→    systemPrompt: generateMelissaOnboardingPrompt(existingUserData),
    60→    greeting: isReturningUser
    61→      ? `Ciao ${existingUserData?.name}! È bello rivederti! Ho già le tue informazioni. Vuoi cambiare qualcosa o andiamo avanti?`
    62→      : 'Ciao! Sono Melissa, piacere di conoscerti! Come ti chiami?',
    63→  };
    64→}
    65→
    66→function WelcomeContent() {
    67→  const router = useRouter();
    68→  const searchParams = useSearchParams();
    69→  const isReplay = searchParams.get('replay') === 'true';
